qss:
QWidget { background: #030804; color: #d5ffd9; font-family: Segoe UI, Arial, sans-serif; font-size: 10pt; }
QMainWindow, QDialog { background: #030804; }
QGroupBox { background: #061408; border: 1px solid #1d5c29; border-radius: 8px; margin-top: 12px; padding: 10px; font-weight: bold; }
QGroupBox::title { subcontrol-origin: margin; left: 12px; padding: 0 4px; color: #2aff6a; }
QTabWidget::pane { border: 1px solid #1d5c29; background: #061408; }
QTabBar::tab { background: #020b03; color: #d5ffd9; padding: 8px 14px; border: 1px solid #1d5c29; border-bottom: none; min-width: 100px; }
QTabBar::tab:selected { background: #0e6420; color: #001b05; font-weight: bold; }
QTabBar::tab:hover { background: #0b2b11; color: #001b05; }
QPushButton { background: #0b2b11; color: #001b05; border: 1px solid #2aff6a; border-radius: 6px; padding: 7px 12px; font-weight: 600; }
QPushButton:hover { background: #2aff6a; color: #001b05; }
QPushButton:disabled { background: #245c2d; color: #020b03; border-color: #1d5c29; }
QLineEdit, QTextEdit, QTextBrowser, QPlainTextEdit, QComboBox, QSpinBox, QDoubleSpinBox { background: #020b03; color: #d5ffd9; border: 1px solid #1d5c29; border-radius: 5px; padding: 5px; selection-background-color: #2aff6a; selection-color: #001b05; }
QComboBox QAbstractItemView { background: #020b03; color: #d5ffd9; selection-background-color: #2aff6a; selection-color: #001b05; border: 1px solid #1d5c29; }
QTableWidget { background: #020b03; alternate-background-color: #061408; color: #d5ffd9; gridline-color: #1d5c29; selection-background-color: #2aff6a; selection-color: #001b05; }
QHeaderView::section { background: #0e6420; color: #001b05; padding: 6px; border: 1px solid #1d5c29; font-weight: bold; }
QScrollBar:vertical { background: #061408; width: 14px; }
QScrollBar::handle:vertical { background: #2aff6a; border-radius: 6px; min-height: 24px; }
QScrollBar:horizontal { background: #061408; height: 14px; }
QScrollBar::handle:horizontal { background: #2aff6a; border-radius: 6px; min-width: 24px; }
QCheckBox { spacing: 6px; }
QLabel { color: #d5ffd9; }
